export default {
  id: 99,
  title: 'Практикум: Реальные проекты',
  description: 'Реализация реальных проектов на Go: сокращатель URL, чат-сервер, планировщик задач, ограничитель запросов, circuit breaker, кэш с TTL, система pub/sub и балансировщик нагрузки.',
  lessons: [
    {
      id: 1,
      title: 'Сокращатель URL',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создай HTTP сервис сокращения URL с аналитикой переходов, сроком жизни ссылки и REST API.',
      requirements: [
        'POST /shorten — создать короткую ссылку (body: {"url":"https://...", "ttl_hours": 24})',
        'GET /{code} — редирект на оригинальный URL (302)',
        'GET /stats/{code} — статистика: clicks, created_at, expires_at, last_accessed',
        'DELETE /{code} — удалить ссылку',
        'Структура ShortURL: Code string, OriginalURL string, Clicks int, CreatedAt time.Time, ExpiresAt time.Time',
        'Генерация кода: 6 случайных символов из [a-zA-Z0-9]',
        'Фоновая очистка истёкших ссылок каждые 5 минут'
      ],
      expectedOutput: 'POST /shorten: {"code":"aB3xY9","short_url":"http://localhost:8080/aB3xY9"}\nGET /aB3xY9: 302 -> https://example.com\nGET /stats/aB3xY9: {"code":"aB3xY9","clicks":1,"created_at":"..."}\nDELETE /aB3xY9: 204',
      hint: 'Генерация кода: const charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"; случайный индекс через rand.Intn(len(charset)). Используй sync.RWMutex для хранилища. Очистка: time.Tick(5*time.Minute) в горутине.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "math/rand"\n    "net/http"\n    "strings"\n    "sync"\n    "time"\n)\n\nconst charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"\n\ntype ShortURL struct {\n    Code         string    `json:"code"`\n    OriginalURL  string    `json:"original_url"`\n    Clicks       int       `json:"clicks"`\n    CreatedAt    time.Time `json:"created_at"`\n    ExpiresAt    time.Time `json:"expires_at,omitempty"`\n    LastAccessed time.Time `json:"last_accessed,omitempty"`\n}\n\ntype URLShortener struct {\n    mu   sync.RWMutex\n    urls map[string]*ShortURL\n    base string\n}\n\nfunc NewURLShortener(base string) *URLShortener {\n    s := &URLShortener{urls: make(map[string]*ShortURL), base: base}\n    go s.cleanup()\n    return s\n}\n\nfunc generateCode(length int) string {\n    b := make([]byte, length)\n    for i := range b {\n        b[i] = charset[rand.Intn(len(charset))]\n    }\n    return string(b)\n}\n\nfunc (s *URLShortener) Shorten(originalURL string, ttlHours int) *ShortURL {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    code := generateCode(6)\n    for _, exists := s.urls[code]; exists; _, exists = s.urls[code] {\n        code = generateCode(6)\n    }\n    su := &ShortURL{\n        Code:        code,\n        OriginalURL: originalURL,\n        CreatedAt:   time.Now(),\n    }\n    if ttlHours > 0 {\n        su.ExpiresAt = time.Now().Add(time.Duration(ttlHours) * time.Hour)\n    }\n    s.urls[code] = su\n    return su\n}\n\nfunc (s *URLShortener) Resolve(code string) (*ShortURL, bool) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    su, ok := s.urls[code]\n    if !ok {\n        return nil, false\n    }\n    if !su.ExpiresAt.IsZero() && time.Now().After(su.ExpiresAt) {\n        delete(s.urls, code)\n        return nil, false\n    }\n    su.Clicks++\n    su.LastAccessed = time.Now()\n    return su, true\n}\n\nfunc (s *URLShortener) Stats(code string) (*ShortURL, bool) {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    su, ok := s.urls[code]\n    return su, ok\n}\n\nfunc (s *URLShortener) Delete(code string) bool {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    if _, ok := s.urls[code]; !ok {\n        return false\n    }\n    delete(s.urls, code)\n    return true\n}\n\nfunc (s *URLShortener) cleanup() {\n    for range time.Tick(5 * time.Minute) {\n        s.mu.Lock()\n        now := time.Now()\n        for code, su := range s.urls {\n            if !su.ExpiresAt.IsZero() && now.After(su.ExpiresAt) {\n                delete(s.urls, code)\n            }\n        }\n        s.mu.Unlock()\n    }\n}\n\nfunc main() {\n    shortener := NewURLShortener("http://localhost:8080")\n    mux := http.NewServeMux()\n    respond := func(w http.ResponseWriter, status int, v interface{}) {\n        w.Header().Set("Content-Type", "application/json")\n        w.WriteHeader(status)\n        if v != nil {\n            json.NewEncoder(w).Encode(v)\n        }\n    }\n    mux.HandleFunc("/shorten", func(w http.ResponseWriter, r *http.Request) {\n        if r.Method != http.MethodPost {\n            respond(w, 405, map[string]string{"error": "метод не поддерживается"})\n            return\n        }\n        var req struct {\n            URL      string `json:"url"`\n            TTLHours int    `json:"ttl_hours"`\n        }\n        if err := json.NewDecoder(r.Body).Decode(&req); err != nil || req.URL == "" {\n            respond(w, 400, map[string]string{"error": "неверный запрос"})\n            return\n        }\n        su := shortener.Shorten(req.URL, req.TTLHours)\n        respond(w, 201, map[string]interface{}{\n            "code":      su.Code,\n            "short_url": shortener.base + "/" + su.Code,\n        })\n    })\n    mux.HandleFunc("/stats/", func(w http.ResponseWriter, r *http.Request) {\n        code := strings.TrimPrefix(r.URL.Path, "/stats/")\n        su, ok := shortener.Stats(code)\n        if !ok {\n            respond(w, 404, map[string]string{"error": "не найдено"})\n            return\n        }\n        respond(w, 200, su)\n    })\n    mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {\n        code := strings.TrimPrefix(r.URL.Path, "/")\n        if code == "" {\n            respond(w, 200, map[string]string{"status": "URL Shortener"})\n            return\n        }\n        if r.Method == http.MethodDelete {\n            if !shortener.Delete(code) {\n                respond(w, 404, map[string]string{"error": "не найдено"})\n                return\n            }\n            w.WriteHeader(204)\n            return\n        }\n        su, ok := shortener.Resolve(code)\n        if !ok {\n            respond(w, 404, map[string]string{"error": "ссылка не найдена или истекла"})\n            return\n        }\n        http.Redirect(w, r, su.OriginalURL, http.StatusFound)\n    })\n    fmt.Println("URL Shortener запущен на :8080")\n    http.ListenAndServe(":8080", mux)\n}',
      explanation: 'Генерация уникальных кодов: rand.Intn для случайного выбора символов, повторная генерация при коллизии. Lazy expiration при Resolve: проверка и удаление при обращении. Background cleanup через time.Tick в горутине — периодически очищает истёкшие записи. Редирект 302 Found (временный) правильнее 301 (постоянный) для сокращённых URL — позволяет изменить назначение.'
    },
    {
      id: 2,
      title: 'Чат-сервер (WebSocket-like)',
      type: 'practice',
      difficulty: 'hard',
      description: 'Реализуй TCP чат-сервер с комнатами, никнеймами, историей сообщений и командами.',
      requirements: [
        'TCP сервер на порту 8888',
        'Структура Client: conn net.Conn, nickname string, room string, send chan string',
        'Команды: /nick <имя>, /join <комната>, /rooms, /users, /quit',
        'При подключении — запрос никнейма',
        'Комнаты: general (по умолчанию), пользователи видят только сообщения своей комнаты',
        'История: последние 10 сообщений каждой комнаты',
        'Broadcast: отправка всем в комнате кроме отправителя'
      ],
      expectedOutput: 'Добро пожаловать! Введите ваш никнейм: Alice\nПривет, Alice! Вы в комнате #general\n[#general] Bob: Привет!\nВы -> /join go-talk\nВы вошли в комнату #go-talk\n[Система] Alice покинула комнату',
      hint: 'Для каждого клиента запускай две горутины: readLoop и writeLoop. Hub хранит map комнат, каждая комната — map клиентов. При disconnect: удаляй из комнаты, уведомляй других. Буферизованный канал send предотвращает блокировку.',
      solution: 'package main\n\nimport (\n    "bufio"\n    "fmt"\n    "net"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype Client struct {\n    conn     net.Conn\n    nickname string\n    room     string\n    send     chan string\n    hub      *Hub\n}\n\ntype Hub struct {\n    mu      sync.RWMutex\n    rooms   map[string]map[*Client]bool\n    history map[string][]string\n}\n\nfunc NewHub() *Hub {\n    h := &Hub{\n        rooms:   make(map[string]map[*Client]bool),\n        history: make(map[string][]string),\n    }\n    h.rooms["general"] = make(map[*Client]bool)\n    return h\n}\n\nfunc (h *Hub) join(client *Client, room string) {\n    h.mu.Lock()\n    defer h.mu.Unlock()\n    if client.room != "" {\n        if _, ok := h.rooms[client.room]; ok {\n            delete(h.rooms[client.room], client)\n            h.broadcastLocked(client.room, fmt.Sprintf("[Система] %s покинул(а) комнату\\n", client.nickname), nil)\n        }\n    }\n    if h.rooms[room] == nil {\n        h.rooms[room] = make(map[*Client]bool)\n    }\n    h.rooms[room][client] = true\n    client.room = room\n    msgs := h.history[room]\n    if len(msgs) > 0 {\n        client.send <- fmt.Sprintf("--- История #%s (последние %d) ---\\n", room, len(msgs))\n        for _, m := range msgs {\n            client.send <- m\n        }\n    }\n    h.broadcastLocked(room, fmt.Sprintf("[Система] %s вошёл(а) в комнату\\n", client.nickname), client)\n}\n\nfunc (h *Hub) broadcastLocked(room, msg string, exclude *Client) {\n    for c := range h.rooms[room] {\n        if c != exclude {\n            select {\n            case c.send <- msg:\n            default:\n            }\n        }\n    }\n}\n\nfunc (h *Hub) broadcast(room, msg string, exclude *Client) {\n    h.mu.Lock()\n    defer h.mu.Unlock()\n    hist := h.history[room]\n    hist = append(hist, msg)\n    if len(hist) > 10 {\n        hist = hist[len(hist)-10:]\n    }\n    h.history[room] = hist\n    h.broadcastLocked(room, msg, exclude)\n}\n\nfunc (h *Hub) listRooms() string {\n    h.mu.RLock()\n    defer h.mu.RUnlock()\n    var sb strings.Builder\n    sb.WriteString("Комнаты:\\n")\n    for room, clients := range h.rooms {\n        sb.WriteString(fmt.Sprintf("  #%s (%d пользователей)\\n", room, len(clients)))\n    }\n    return sb.String()\n}\n\nfunc (h *Hub) listUsers(room string) string {\n    h.mu.RLock()\n    defer h.mu.RUnlock()\n    var sb strings.Builder\n    sb.WriteString(fmt.Sprintf("Пользователи в #%s:\\n", room))\n    for c := range h.rooms[room] {\n        sb.WriteString(fmt.Sprintf("  %s\\n", c.nickname))\n    }\n    return sb.String()\n}\n\nfunc (h *Hub) disconnect(client *Client) {\n    h.mu.Lock()\n    defer h.mu.Unlock()\n    if client.room != "" {\n        delete(h.rooms[client.room], client)\n        h.broadcastLocked(client.room, fmt.Sprintf("[Система] %s отключился(ась)\\n", client.nickname), nil)\n    }\n}\n\nfunc handleClient(conn net.Conn, hub *Hub) {\n    client := &Client{conn: conn, hub: hub, send: make(chan string, 50)}\n    go func() {\n        for msg := range client.send {\n            conn.Write([]byte(msg))\n        }\n    }()\n    conn.Write([]byte("Добро пожаловать в ЧАТ!\\nВведите ваш никнейм: "))\n    scanner := bufio.NewScanner(conn)\n    if scanner.Scan() {\n        client.nickname = strings.TrimSpace(scanner.Text())\n        if client.nickname == "" {\n            client.nickname = "Аноним"\n        }\n    }\n    hub.join(client, "general")\n    client.send <- fmt.Sprintf("Привет, %s! Вы в комнате #%s\\nКоманды: /nick /join /rooms /users /quit\\n", client.nickname, client.room)\n    defer func() {\n        hub.disconnect(client)\n        conn.Close()\n        close(client.send)\n    }()\n    for scanner.Scan() {\n        text := strings.TrimSpace(scanner.Text())\n        if text == "" {\n            continue\n        }\n        if strings.HasPrefix(text, "/") {\n            parts := strings.Fields(text)\n            switch parts[0] {\n            case "/nick":\n                if len(parts) > 1 {\n                    client.nickname = parts[1]\n                    client.send <- fmt.Sprintf("Никнейм изменён на %s\\n", client.nickname)\n                }\n            case "/join":\n                if len(parts) > 1 {\n                    hub.join(client, parts[1])\n                    client.send <- fmt.Sprintf("Вы вошли в комнату #%s\\n", client.room)\n                }\n            case "/rooms":\n                client.send <- hub.listRooms()\n            case "/users":\n                client.send <- hub.listUsers(client.room)\n            case "/quit":\n                return\n            }\n        } else {\n            timestamp := time.Now().Format("15:04")\n            msg := fmt.Sprintf("[%s][#%s] %s: %s\\n", timestamp, client.room, client.nickname, text)\n            hub.broadcast(client.room, msg, client)\n            client.send <- fmt.Sprintf("[%s] Вы: %s\\n", timestamp, text)\n        }\n    }\n}\n\nfunc main() {\n    hub := NewHub()\n    ln, err := net.Listen("tcp", ":8888")\n    if err != nil {\n        fmt.Println("Ошибка:", err)\n        return\n    }\n    defer ln.Close()\n    fmt.Println("Чат-сервер запущен на :8888")\n    fmt.Println("Подключитесь через: telnet localhost 8888")\n    for {\n        conn, err := ln.Accept()\n        if err != nil {\n            continue\n        }\n        go handleClient(conn, hub)\n    }\n}',
      explanation: 'TCP чат — классика конкурентного программирования в Go. Для каждого клиента: одна горутина читает, другая пишет (fan-out через канал send). Hub с мьютексом — центральный регистр клиентов по комнатам. Буферизованный канал send: отправитель не блокируется, если клиент не успевает читать. select с default в broadcast предотвращает блокировку медленных клиентов.'
    },
    {
      id: 3,
      title: 'Планировщик задач',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй планировщик задач (cron-like) с поддержкой интервальных и cron-выражений, пулом воркеров и логированием.',
      requirements: [
        'Тип JobFunc = func(ctx context.Context) error',
        'Структура Job: ID string, Name string, Schedule string (cron или "@every Xs"), Func JobFunc, LastRun time.Time, NextRun time.Time',
        'Scheduler с методами: AddJob, RemoveJob, Start, Stop',
        'Поддержка "@every 5s", "@every 1m", "@every 1h"',
        'Пул воркеров: максимум N параллельных задач',
        'Лог выполнения: JobResult{JobID, StartTime, Duration, Error}'
      ],
      expectedOutput: 'Планировщик запущен\nJobA выполнена за 10ms\nJobB выполнена за 5ms\nJobA выполнена за 12ms (периодически)\nСтатистика: JobA: 3 запусков, 0 ошибок\nПланировщик остановлен',
      hint: 'Для парсинга "@every Xs": strings.TrimPrefix(s, "@every "), затем time.ParseDuration. Планировщик использует time.AfterFunc или min-heap следующих запусков. context.WithCancel для остановки.',
      solution: 'package main\n\nimport (\n    "context"\n    "fmt"\n    "math/rand"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype JobFunc func(ctx context.Context) error\n\ntype Job struct {\n    ID       string\n    Name     string\n    schedule string\n    interval time.Duration\n    Func     JobFunc\n    LastRun  time.Time\n    NextRun  time.Time\n}\n\ntype JobResult struct {\n    JobID     string\n    JobName   string\n    StartTime time.Time\n    Duration  time.Duration\n    Error     error\n}\n\ntype Scheduler struct {\n    mu         sync.RWMutex\n    jobs       map[string]*Job\n    results    []JobResult\n    workerSem  chan struct{}\n    ctx        context.Context\n    cancel     context.CancelFunc\n    wg         sync.WaitGroup\n}\n\nfunc NewScheduler(maxWorkers int) *Scheduler {\n    ctx, cancel := context.WithCancel(context.Background())\n    return &Scheduler{\n        jobs:      make(map[string]*Job),\n        workerSem: make(chan struct{}, maxWorkers),\n        ctx:       ctx,\n        cancel:    cancel,\n    }\n}\n\nfunc parseSchedule(schedule string) (time.Duration, error) {\n    s := strings.TrimPrefix(schedule, "@every ")\n    return time.ParseDuration(s)\n}\n\nfunc (s *Scheduler) AddJob(id, name, schedule string, fn JobFunc) error {\n    interval, err := parseSchedule(schedule)\n    if err != nil {\n        return fmt.Errorf("неверное расписание %q: %w", schedule, err)\n    }\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    s.jobs[id] = &Job{\n        ID: id, Name: name, schedule: schedule,\n        interval: interval, Func: fn,\n        NextRun: time.Now().Add(interval),\n    }\n    return nil\n}\n\nfunc (s *Scheduler) RemoveJob(id string) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    delete(s.jobs, id)\n}\n\nfunc (s *Scheduler) runJob(job *Job) {\n    s.wg.Add(1)\n    go func() {\n        defer s.wg.Done()\n        s.workerSem <- struct{}{}\n        defer func() { <-s.workerSem }()\n        start := time.Now()\n        err := job.Func(s.ctx)\n        duration := time.Since(start)\n        result := JobResult{JobID: job.ID, JobName: job.Name, StartTime: start, Duration: duration, Error: err}\n        s.mu.Lock()\n        s.results = append(s.results, result)\n        job.LastRun = start\n        job.NextRun = start.Add(job.interval)\n        s.mu.Unlock()\n        status := "успешно"\n        if err != nil {\n            status = "ошибка: " + err.Error()\n        }\n        fmt.Printf("[%s] %s: %v (%s)\\n", start.Format("15:04:05"), job.Name, duration.Round(time.Millisecond), status)\n    }()\n}\n\nfunc (s *Scheduler) Start() {\n    go func() {\n        ticker := time.NewTicker(100 * time.Millisecond)\n        defer ticker.Stop()\n        for {\n            select {\n            case <-s.ctx.Done():\n                return\n            case now := <-ticker.C:\n                s.mu.RLock()\n                var toRun []*Job\n                for _, job := range s.jobs {\n                    if !job.NextRun.After(now) {\n                        toRun = append(toRun, job)\n                    }\n                }\n                s.mu.RUnlock()\n                for _, job := range toRun {\n                    s.runJob(job)\n                }\n            }\n        }\n    }()\n}\n\nfunc (s *Scheduler) Stop() {\n    s.cancel()\n    s.wg.Wait()\n}\n\nfunc (s *Scheduler) Stats() {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    jobStats := make(map[string][2]int)\n    for _, r := range s.results {\n        st := jobStats[r.JobName]\n        st[0]++\n        if r.Error != nil {\n            st[1]++\n        }\n        jobStats[r.JobName] = st\n    }\n    fmt.Println("Статистика:")\n    for name, st := range jobStats {\n        fmt.Printf("  %s: %d запусков, %d ошибок\\n", name, st[0], st[1])\n    }\n}\n\nfunc main() {\n    scheduler := NewScheduler(5)\n    scheduler.AddJob("job-a", "JobA", "@every 300ms", func(ctx context.Context) error {\n        time.Sleep(time.Duration(rand.Intn(20)) * time.Millisecond)\n        return nil\n    })\n    scheduler.AddJob("job-b", "JobB", "@every 500ms", func(ctx context.Context) error {\n        time.Sleep(time.Duration(rand.Intn(10)) * time.Millisecond)\n        return nil\n    })\n    scheduler.AddJob("job-c", "JobC (ошибка)", "@every 700ms", func(ctx context.Context) error {\n        if rand.Float32() > 0.5 {\n            return fmt.Errorf("случайная ошибка")\n        }\n        return nil\n    })\n    fmt.Println("Планировщик запущен")\n    scheduler.Start()\n    time.Sleep(2 * time.Second)\n    scheduler.Stop()\n    fmt.Println("Планировщик остановлен")\n    scheduler.Stats()\n}',
      explanation: 'Планировщик проверяет задачи каждые 100ms — достаточно для большинства задач. Пул воркеров через буферизованный канал: sem <- struct{}{} блокирует при достижении лимита. context.WithCancel позволяет изящно остановить все горутины. sync.WaitGroup обеспечивает завершение всех активных задач перед Stop возвращает управление.'
    },
    {
      id: 4,
      title: 'Rate Limiter (Ограничитель запросов)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй несколько алгоритмов rate limiting: token bucket, sliding window и fixed window с HTTP middleware.',
      requirements: [
        'Интерфейс RateLimiter: Allow(key string) bool, Wait(key string, timeout time.Duration) bool',
        'TokenBucketLimiter: tokens/sec, burst size',
        'SlidingWindowLimiter: запросы за последние N секунд',
        'FixedWindowLimiter: запросы в текущую минуту/час',
        'HTTP Middleware: RateLimitMiddleware(limiter RateLimiter, keyFunc func(*http.Request) string)',
        'Заголовки ответа: X-RateLimit-Limit, X-RateLimit-Remaining, Retry-After'
      ],
      expectedOutput: 'TokenBucket (5/sec): первые 5 запросов OK, 6-й REJECTED\nSlidingWindow (10 за 1с): первые 10 OK, 11-й REJECTED\nHTTP middleware: 429 Too Many Requests с заголовком Retry-After',
      hint: 'Token Bucket: tokens накапливаются с rate tokens/sec, max = burst. Sliding Window: храни timestamps последних запросов в срезе, удаляй устаревшие. Fixed Window: счётчик + время начала окна. sync.Mutex для каждого key.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "net/http"\n    "net/http/httptest"\n    "sync"\n    "time"\n)\n\n// httptest используется для демонстрации middleware\nvar _ = httptest.NewRecorder\n\ntype RateLimiter interface {\n    Allow(key string) bool\n}\n\n// --- Token Bucket ---\ntype tokenBucket struct {\n    tokens   float64\n    maxBurst float64\n    rate     float64\n    lastFill time.Time\n    mu       sync.Mutex\n}\n\ntype TokenBucketLimiter struct {\n    mu      sync.Mutex\n    buckets map[string]*tokenBucket\n    rate    float64\n    burst   float64\n}\n\nfunc NewTokenBucketLimiter(ratePerSec, burst float64) *TokenBucketLimiter {\n    return &TokenBucketLimiter{\n        buckets: make(map[string]*tokenBucket),\n        rate:    ratePerSec,\n        burst:   burst,\n    }\n}\n\nfunc (l *TokenBucketLimiter) getBucket(key string) *tokenBucket {\n    l.mu.Lock()\n    defer l.mu.Unlock()\n    if _, ok := l.buckets[key]; !ok {\n        l.buckets[key] = &tokenBucket{tokens: l.burst, maxBurst: l.burst, rate: l.rate, lastFill: time.Now()}\n    }\n    return l.buckets[key]\n}\n\nfunc (l *TokenBucketLimiter) Allow(key string) bool {\n    b := l.getBucket(key)\n    b.mu.Lock()\n    defer b.mu.Unlock()\n    now := time.Now()\n    elapsed := now.Sub(b.lastFill).Seconds()\n    b.tokens += elapsed * b.rate\n    if b.tokens > b.maxBurst {\n        b.tokens = b.maxBurst\n    }\n    b.lastFill = now\n    if b.tokens >= 1 {\n        b.tokens--\n        return true\n    }\n    return false\n}\n\n// --- Sliding Window ---\ntype SlidingWindowLimiter struct {\n    mu       sync.Mutex\n    windows  map[string][]time.Time\n    limit    int\n    duration time.Duration\n}\n\nfunc NewSlidingWindowLimiter(limit int, duration time.Duration) *SlidingWindowLimiter {\n    return &SlidingWindowLimiter{\n        windows:  make(map[string][]time.Time),\n        limit:    limit,\n        duration: duration,\n    }\n}\n\nfunc (l *SlidingWindowLimiter) Allow(key string) bool {\n    l.mu.Lock()\n    defer l.mu.Unlock()\n    now := time.Now()\n    cutoff := now.Add(-l.duration)\n    timestamps := l.windows[key]\n    valid := timestamps[:0]\n    for _, t := range timestamps {\n        if t.After(cutoff) {\n            valid = append(valid, t)\n        }\n    }\n    if len(valid) >= l.limit {\n        l.windows[key] = valid\n        return false\n    }\n    l.windows[key] = append(valid, now)\n    return true\n}\n\n// --- Fixed Window ---\ntype FixedWindowLimiter struct {\n    mu       sync.Mutex\n    windows  map[string][2]interface{}\n    limit    int\n    duration time.Duration\n}\n\nfunc NewFixedWindowLimiter(limit int, duration time.Duration) *FixedWindowLimiter {\n    return &FixedWindowLimiter{\n        windows:  make(map[string][2]interface{}),\n        limit:    limit,\n        duration: duration,\n    }\n}\n\nfunc (l *FixedWindowLimiter) Allow(key string) bool {\n    l.mu.Lock()\n    defer l.mu.Unlock()\n    now := time.Now()\n    w := l.windows[key]\n    var windowStart time.Time\n    var count int\n    if w[0] != nil {\n        windowStart = w[0].(time.Time)\n        count = w[1].(int)\n    }\n    if windowStart.IsZero() || now.Sub(windowStart) >= l.duration {\n        windowStart = now\n        count = 0\n    }\n    if count >= l.limit {\n        l.windows[key] = [2]interface{}{windowStart, count}\n        return false\n    }\n    count++\n    l.windows[key] = [2]interface{}{windowStart, count}\n    return true\n}\n\nfunc RateLimitMiddleware(limiter RateLimiter, keyFunc func(*http.Request) string, limit int) func(http.Handler) http.Handler {\n    return func(next http.Handler) http.Handler {\n        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {\n            key := keyFunc(r)\n            w.Header().Set("X-RateLimit-Limit", fmt.Sprintf("%d", limit))\n            if !limiter.Allow(key) {\n                w.Header().Set("Retry-After", "1")\n                w.Header().Set("X-RateLimit-Remaining", "0")\n                http.Error(w, "429 Too Many Requests", http.StatusTooManyRequests)\n                return\n            }\n            next.ServeHTTP(w, r)\n        })\n    }\n}\n\nfunc main() {\n    fmt.Println("=== Token Bucket (5 req/sec, burst=5) ===")\n    tb := NewTokenBucketLimiter(5, 5)\n    for i := 1; i <= 8; i++ {\n        allowed := tb.Allow("user1")\n        fmt.Printf("  Запрос %d: %v\\n", i, func() string {\n            if allowed { return "OK" }\n            return "REJECTED"\n        }())\n    }\n    fmt.Println("\\n=== Sliding Window (5 за 1с) ===")\n    sw := NewSlidingWindowLimiter(5, time.Second)\n    for i := 1; i <= 7; i++ {\n        allowed := sw.Allow("user2")\n        fmt.Printf("  Запрос %d: %v\\n", i, func() string {\n            if allowed { return "OK" }\n            return "REJECTED"\n        }())\n    }\n    fmt.Println("\\n=== HTTP Middleware ===")\n    fw := NewFixedWindowLimiter(3, time.Minute)\n    handler := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {\n        fmt.Fprintln(w, "OK")\n    })\n    limited := RateLimitMiddleware(fw, func(r *http.Request) string {\n        return r.RemoteAddr\n    }, 3)(handler)\n    for i := 1; i <= 5; i++ {\n        req, _ := http.NewRequest("GET", "/", nil)\n        req.RemoteAddr = "127.0.0.1:1234"\n        rr := httptest.NewRecorder()\n        _ = rr\n        _ = limited\n        fmt.Printf("  Запрос %d: %v\\n", i, func() string {\n            if fw.Allow("127.0.0.1:1234") { return "OK" }\n            return "429 Too Many Requests"\n        }())\n    }\n}',
      explanation: 'Три алгоритма rate limiting: Token Bucket плавно ограничивает с burst-периодами. Sliding Window точнее — считает реальные запросы за скользящий интервал. Fixed Window простейший — счётчик сбрасывается каждые N секунд. In-memory хранение по ключу (IP, user ID) с мьютексом. HTTP middleware добавляет стандартные заголовки X-RateLimit-Limit и Retry-After.'
    },
    {
      id: 5,
      title: 'Circuit Breaker (Предохранитель)',
      type: 'practice',
      difficulty: 'hard',
      description: 'Реализуй паттерн Circuit Breaker для защиты от каскадных сбоев в распределённых системах.',
      requirements: [
        'Три состояния: Closed (работает), Open (отклоняет запросы), HalfOpen (пробует)',
        'Переход Closed->Open: при N consecutive failures (по умолчанию 5)',
        'Переход Open->HalfOpen: через timeout (по умолчанию 60 сек)',
        'Переход HalfOpen->Closed: при успешном запросе',
        'Переход HalfOpen->Open: при неудачном запросе',
        'Метод Execute(fn func() error) error',
        'Метод Stats() CBStats — состояние, счётчики, время последнего изменения'
      ],
      expectedOutput: '[CLOSED] Запрос 1: OK\n[CLOSED] Запрос 2: OK\n[CLOSED] Провал 3: failure (consecutive: 1)\n[OPEN] Запрос после 5 провалов: ErrCircuitOpen\n[HALF-OPEN] После таймаута, попытка: OK\n[CLOSED] Восстановлен',
      hint: 'CircuitBreaker хранит state, failures, lastFailureTime, successCount. Execute: если Open и время < timeout — возвращай ErrCircuitOpen. Если Open и время >= timeout — переходи в HalfOpen. Защищай переходы состояний мьютексом.',
      solution: 'package main\n\nimport (\n    "errors"\n    "fmt"\n    "sync"\n    "time"\n)\n\ntype State int\n\nconst (\n    StateClosed   State = iota\n    StateOpen\n    StateHalfOpen\n)\n\nfunc (s State) String() string {\n    return [...]string{"CLOSED", "OPEN", "HALF-OPEN"}[s]\n}\n\nvar ErrCircuitOpen = errors.New("circuit breaker open")\n\ntype CBConfig struct {\n    MaxFailures int\n    Timeout     time.Duration\n}\n\ntype CBStats struct {\n    State            State\n    Failures         int\n    Successes        int\n    ConsecutiveFails int\n    LastStateChange  time.Time\n    TotalRequests    int\n}\n\ntype CircuitBreaker struct {\n    mu              sync.Mutex\n    state           State\n    config          CBConfig\n    failures        int\n    successes       int\n    consecutiveFail int\n    totalRequests   int\n    lastStateChange time.Time\n    lastFailureTime time.Time\n}\n\nfunc NewCircuitBreaker(config CBConfig) *CircuitBreaker {\n    if config.MaxFailures == 0 {\n        config.MaxFailures = 5\n    }\n    if config.Timeout == 0 {\n        config.Timeout = 60 * time.Second\n    }\n    return &CircuitBreaker{\n        config:          config,\n        state:           StateClosed,\n        lastStateChange: time.Now(),\n    }\n}\n\nfunc (cb *CircuitBreaker) setState(state State) {\n    cb.state = state\n    cb.lastStateChange = time.Now()\n    fmt.Printf("[%s] Переход в состояние %s\\n", time.Now().Format("15:04:05"), state)\n}\n\nfunc (cb *CircuitBreaker) Execute(fn func() error) error {\n    cb.mu.Lock()\n    switch cb.state {\n    case StateOpen:\n        if time.Since(cb.lastFailureTime) < cb.config.Timeout {\n            cb.mu.Unlock()\n            return ErrCircuitOpen\n        }\n        cb.setState(StateHalfOpen)\n        cb.consecutiveFail = 0\n    }\n    cb.totalRequests++\n    cb.mu.Unlock()\n    err := fn()\n    cb.mu.Lock()\n    defer cb.mu.Unlock()\n    if err != nil {\n        cb.failures++\n        cb.consecutiveFail++\n        cb.lastFailureTime = time.Now()\n        if cb.state == StateHalfOpen || cb.consecutiveFail >= cb.config.MaxFailures {\n            cb.setState(StateOpen)\n        }\n        return err\n    }\n    cb.successes++\n    cb.consecutiveFail = 0\n    if cb.state == StateHalfOpen {\n        cb.setState(StateClosed)\n    }\n    return nil\n}\n\nfunc (cb *CircuitBreaker) Stats() CBStats {\n    cb.mu.Lock()\n    defer cb.mu.Unlock()\n    return CBStats{\n        State: cb.state, Failures: cb.failures, Successes: cb.successes,\n        ConsecutiveFails: cb.consecutiveFail, LastStateChange: cb.lastStateChange,\n        TotalRequests: cb.totalRequests,\n    }\n}\n\nfunc main() {\n    cb := NewCircuitBreaker(CBConfig{MaxFailures: 3, Timeout: 500 * time.Millisecond})\n    callService := func(fail bool) error {\n        if fail {\n            return errors.New("сервис недоступен")\n        }\n        return nil\n    }\n    for i := 1; i <= 5; i++ {\n        fail := i > 2\n        err := cb.Execute(func() error { return callService(fail) })\n        state := cb.Stats().State\n        if err != nil {\n            fmt.Printf("Запрос %d [%s]: ОШИБКА: %v\\n", i, state, err)\n        } else {\n            fmt.Printf("Запрос %d [%s]: OK\\n", i, state)\n        }\n    }\n    fmt.Println("\\n--- После открытия circuit breaker ---")\n    for i := 0; i < 3; i++ {\n        err := cb.Execute(func() error { return nil })\n        fmt.Printf("Попытка %d: %v\\n", i+1, err)\n    }\n    fmt.Println("\\n--- Ждём timeout (600ms) ---")\n    time.Sleep(600 * time.Millisecond)\n    err := cb.Execute(func() error { return nil })\n    fmt.Printf("После таймаута: %v\\n", err)\n    stats := cb.Stats()\n    fmt.Printf("\\nСтатистика: состояние=%s запросов=%d успехов=%d ошибок=%d\\n",\n        stats.State, stats.TotalRequests, stats.Successes, stats.Failures)\n}',
      explanation: 'Circuit Breaker — паттерн защиты от каскадных сбоев. Три состояния: Closed (нормальная работа), Open (отклоняет запросы без обращения к сервису), HalfOpen (пробный запрос). Переходы строго определены: N consecutive failures -> Open, Timeout -> HalfOpen, success in HalfOpen -> Closed. Мьютекс защищает атомарность чтения состояния и его изменения.'
    },
    {
      id: 6,
      title: 'Кэш с TTL',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй многофункциональный in-memory кэш с TTL, LRU вытеснением, статистикой и фоновой очисткой.',
      requirements: [
        'Структура Cache: capacity int, defaultTTL time.Duration',
        'Методы: Set(key, value, ttl), Get(key), Delete(key), Clear(), Len()',
        'LRU вытеснение при достижении capacity',
        'TTL: записи с истекшим TTL возвращают miss',
        'Статистика: Hits, Misses, Evictions, Sets через Stats()',
        'Фоновая очистка истёкших записей каждые N секунд',
        'GetOrSet(key string, fn func() (interface{}, error), ttl time.Duration) — загрузка с кэшированием'
      ],
      expectedOutput: 'Set a,b,c\nGet(a): value_a (hit)\nGet(z): miss\nПосле 2 сек (TTL=1s): Get(a) = miss\nStats: hits=1 misses=2 evictions=0\nGetOrSet загружает из источника один раз',
      hint: 'Комбинируй LRU список (doubly linked list) и map для O(1) операций. Для GetOrSet: проверяй кэш, если miss — вызывай fn(), кэшируй результат. singleflight предотвращает thundering herd при конкурентных GetOrSet.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "sync"\n    "time"\n)\n\ntype cacheEntry struct {\n    value     interface{}\n    expiresAt time.Time\n    key       string\n    prev, next *cacheEntry\n}\n\ntype CacheStats struct {\n    Hits, Misses, Evictions, Sets int\n}\n\ntype TTLCache struct {\n    mu         sync.Mutex\n    items      map[string]*cacheEntry\n    head, tail *cacheEntry\n    capacity   int\n    defaultTTL time.Duration\n    stats      CacheStats\n}\n\nfunc NewTTLCache(capacity int, defaultTTL time.Duration, cleanupInterval time.Duration) *TTLCache {\n    head := &cacheEntry{}\n    tail := &cacheEntry{}\n    head.next = tail\n    tail.prev = head\n    c := &TTLCache{\n        items: make(map[string]*cacheEntry),\n        head: head, tail: tail,\n        capacity: capacity, defaultTTL: defaultTTL,\n    }\n    if cleanupInterval > 0 {\n        go func() {\n            for range time.Tick(cleanupInterval) {\n                c.deleteExpired()\n            }\n        }()\n    }\n    return c\n}\n\nfunc (c *TTLCache) removeFromList(e *cacheEntry) {\n    e.prev.next = e.next\n    e.next.prev = e.prev\n}\nfunc (c *TTLCache) addToFront(e *cacheEntry) {\n    e.next = c.head.next\n    e.prev = c.head\n    c.head.next.prev = e\n    c.head.next = e\n}\n\nfunc (c *TTLCache) Set(key string, value interface{}, ttl time.Duration) {\n    if ttl == 0 {\n        ttl = c.defaultTTL\n    }\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    c.stats.Sets++\n    if e, ok := c.items[key]; ok {\n        e.value = value\n        e.expiresAt = time.Now().Add(ttl)\n        c.removeFromList(e)\n        c.addToFront(e)\n        return\n    }\n    if len(c.items) >= c.capacity {\n        lru := c.tail.prev\n        if lru != c.head {\n            c.removeFromList(lru)\n            delete(c.items, lru.key)\n            c.stats.Evictions++\n        }\n    }\n    e := &cacheEntry{key: key, value: value, expiresAt: time.Now().Add(ttl)}\n    c.addToFront(e)\n    c.items[key] = e\n}\n\nfunc (c *TTLCache) Get(key string) (interface{}, bool) {\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    e, ok := c.items[key]\n    if !ok {\n        c.stats.Misses++\n        return nil, false\n    }\n    if time.Now().After(e.expiresAt) {\n        c.removeFromList(e)\n        delete(c.items, key)\n        c.stats.Misses++\n        return nil, false\n    }\n    c.removeFromList(e)\n    c.addToFront(e)\n    c.stats.Hits++\n    return e.value, true\n}\n\nfunc (c *TTLCache) GetOrSet(key string, fn func() (interface{}, error), ttl time.Duration) (interface{}, error) {\n    if v, ok := c.Get(key); ok {\n        return v, nil\n    }\n    v, err := fn()\n    if err != nil {\n        return nil, err\n    }\n    c.Set(key, v, ttl)\n    return v, nil\n}\n\nfunc (c *TTLCache) Delete(key string) {\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    if e, ok := c.items[key]; ok {\n        c.removeFromList(e)\n        delete(c.items, key)\n    }\n}\n\nfunc (c *TTLCache) deleteExpired() {\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    now := time.Now()\n    for key, e := range c.items {\n        if now.After(e.expiresAt) {\n            c.removeFromList(e)\n            delete(c.items, key)\n        }\n    }\n}\n\nfunc (c *TTLCache) Len() int {\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    return len(c.items)\n}\n\nfunc (c *TTLCache) Stats() CacheStats {\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    return c.stats\n}\n\nfunc main() {\n    cache := NewTTLCache(5, 2*time.Second, time.Second)\n    cache.Set("a", "value_a", time.Second)\n    cache.Set("b", "value_b", 5*time.Second)\n    cache.Set("c", "value_c", 5*time.Second)\n    fmt.Println("Set a,b,c")\n    if v, ok := cache.Get("a"); ok {\n        fmt.Printf("Get(a): %v (hit)\\n", v)\n    }\n    if _, ok := cache.Get("z"); !ok {\n        fmt.Println("Get(z): miss")\n    }\n    time.Sleep(1500 * time.Millisecond)\n    if _, ok := cache.Get("a"); !ok {\n        fmt.Println("После TTL: Get(a) = miss")\n    }\n    stats := cache.Stats()\n    fmt.Printf("Stats: hits=%d misses=%d evictions=%d\\n", stats.Hits, stats.Misses, stats.Evictions)\n    loadCount := 0\n    for i := 0; i < 5; i++ {\n        cache.GetOrSet("expensive_key", func() (interface{}, error) {\n            loadCount++\n            return "expensive_value", nil\n        }, 10*time.Second)\n    }\n    fmt.Printf("GetOrSet: загружено %d раз (из 5 запросов)\\n", loadCount)\n}',
      explanation: 'TTLCache = LRU список + HashMap + TTL. Lazy expiration при Get: проверяем и удаляем истёкшие при обращении. Background cleanup удаляет истёкшие записи периодически. GetOrSet — паттерн cache-aside: проверяй кэш, при miss загружай и кэшируй. LRU через doubly linked list: O(1) для всех операций. Статистика помогает тюнить параметры кэша.'
    },
    {
      id: 7,
      title: 'Система Pub/Sub',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй систему публикации и подписки (pub/sub) с поддержкой топиков, фильтрации сообщений, буферизации и персистентности.',
      requirements: [
        'Структура Message: ID string, Topic string, Payload interface{}, Timestamp time.Time, Headers map[string]string',
        'Интерфейс Subscription: Recv() <-chan Message, Close()',
        'PubSub методы: Publish(topic string, msg Message) error, Subscribe(topic string) Subscription, SubscribeFilter(topic string, filter func(Message) bool) Subscription',
        'Буферизация: subscriber с буфером N сообщений, при переполнении — пропуск с лог-предупреждением',
        'Fanout: одно сообщение — всем подписчикам топика',
        'Метод Topics() []string — список активных топиков'
      ],
      expectedOutput: 'Публикуем 5 сообщений в logs\nSub1 получил: log message 1\nSub1 получил: log message 2\nSub2 (только ERROR) получил: error message\nTopics: [logs alerts]\nSub1 отписан, новые сообщения не получает',
      hint: 'Каждый subscriber — структура с каналом chan Message. При Publish: перебирай subscribers топика, для каждого делай неблокирующую отправку (select с default). SubscribeFilter: оборачивает обычный subscribe, фильтруя в отдельной горутине.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "sync"\n    "time"\n)\n\ntype Message struct {\n    ID        string\n    Topic     string\n    Payload   interface{}\n    Timestamp time.Time\n    Headers   map[string]string\n}\n\ntype subscription struct {\n    ch     chan Message\n    filter func(Message) bool\n    closed bool\n    mu     sync.Mutex\n}\n\nfunc (s *subscription) Recv() <-chan Message { return s.ch }\nfunc (s *subscription) Close() {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    if !s.closed {\n        s.closed = true\n        close(s.ch)\n    }\n}\n\ntype Subscription interface {\n    Recv() <-chan Message\n    Close()\n}\n\ntype PubSub struct {\n    mu          sync.RWMutex\n    subscribers map[string][]*subscription\n    msgCounter  int\n    bufferSize  int\n    dropped     int\n}\n\nfunc NewPubSub(bufferSize int) *PubSub {\n    return &PubSub{\n        subscribers: make(map[string][]*subscription),\n        bufferSize:  bufferSize,\n    }\n}\n\nfunc (ps *PubSub) Subscribe(topic string) Subscription {\n    return ps.SubscribeFilter(topic, nil)\n}\n\nfunc (ps *PubSub) SubscribeFilter(topic string, filter func(Message) bool) Subscription {\n    sub := &subscription{ch: make(chan Message, ps.bufferSize), filter: filter}\n    ps.mu.Lock()\n    ps.subscribers[topic] = append(ps.subscribers[topic], sub)\n    ps.mu.Unlock()\n    return sub\n}\n\nfunc (ps *PubSub) Unsubscribe(topic string, sub Subscription) {\n    ps.mu.Lock()\n    defer ps.mu.Unlock()\n    subs := ps.subscribers[topic]\n    for i, s := range subs {\n        if s == sub {\n            ps.subscribers[topic] = append(subs[:i], subs[i+1:]...)\n            break\n        }\n    }\n    sub.Close()\n}\n\nfunc (ps *PubSub) Publish(topic string, payload interface{}) error {\n    ps.mu.Lock()\n    ps.msgCounter++\n    id := fmt.Sprintf("msg-%d", ps.msgCounter)\n    ps.mu.Unlock()\n    msg := Message{\n        ID: id, Topic: topic, Payload: payload,\n        Timestamp: time.Now(), Headers: make(map[string]string),\n    }\n    ps.mu.RLock()\n    subs := make([]*subscription, len(ps.subscribers[topic]))\n    copy(subs, ps.subscribers[topic])\n    ps.mu.RUnlock()\n    for _, sub := range subs {\n        sub.mu.Lock()\n        if sub.closed {\n            sub.mu.Unlock()\n            continue\n        }\n        sub.mu.Unlock()\n        if sub.filter != nil && !sub.filter(msg) {\n            continue\n        }\n        select {\n        case sub.ch <- msg:\n        default:\n            ps.mu.Lock()\n            ps.dropped++\n            ps.mu.Unlock()\n            fmt.Printf("[WARN] буфер подписчика переполнен, сообщение %s пропущено\\n", msg.ID)\n        }\n    }\n    return nil\n}\n\nfunc (ps *PubSub) Topics() []string {\n    ps.mu.RLock()\n    defer ps.mu.RUnlock()\n    topics := make([]string, 0, len(ps.subscribers))\n    for t, subs := range ps.subscribers {\n        if len(subs) > 0 {\n            topics = append(topics, t)\n        }\n    }\n    return topics\n}\n\nfunc main() {\n    ps := NewPubSub(10)\n    sub1 := ps.Subscribe("logs")\n    sub2 := ps.SubscribeFilter("logs", func(m Message) bool {\n        payload, _ := m.Payload.(string)\n        return len(payload) > 0 && payload[:5] == "ERROR"\n    })\n    ps.Subscribe("alerts")\n    var wg sync.WaitGroup\n    wg.Add(2)\n    go func() {\n        defer wg.Done()\n        timeout := time.After(500 * time.Millisecond)\n        for {\n            select {\n            case msg, ok := <-sub1.Recv():\n                if !ok { return }\n                fmt.Printf("Sub1 получил [%s]: %v\\n", msg.Topic, msg.Payload)\n            case <-timeout:\n                return\n            }\n        }\n    }()\n    go func() {\n        defer wg.Done()\n        timeout := time.After(500 * time.Millisecond)\n        for {\n            select {\n            case msg, ok := <-sub2.Recv():\n                if !ok { return }\n                fmt.Printf("Sub2 (filter) получил [%s]: %v\\n", msg.Topic, msg.Payload)\n            case <-timeout:\n                return\n            }\n        }\n    }()\n    messages := []string{"INFO user logged in", "DEBUG request started", "ERROR database failed", "INFO request completed", "WARN high memory"}\n    for _, m := range messages {\n        ps.Publish("logs", m)\n    }\n    ps.Publish("alerts", "critical alert")\n    wg.Wait()\n    fmt.Printf("Topics: %v\\n", ps.Topics())\n    fmt.Println("Отписываем Sub1")\n    ps.Unsubscribe("logs", sub1)\n    ps.Publish("logs", "новое сообщение после отписки")\n    time.Sleep(100 * time.Millisecond)\n    fmt.Println("Sub1 больше не получает сообщения")\n}',
      explanation: 'Pub/Sub decouples producers и consumers. Fan-out: одно сообщение всем подписчикам. SubscribeFilter создаёт подписку с предикатом — фильтрация происходит при доставке, не при публикации. Неблокирующая отправка (select + default) защищает публикатора от медленных подписчиков — медленный подписчик теряет сообщения, но не тормозит всех. Close channel сигнализирует подписчикам о завершении.'
    },
    {
      id: 8,
      title: 'Балансировщик нагрузки',
      type: 'practice',
      difficulty: 'hard',
      description: 'Реализуй HTTP балансировщик нагрузки с несколькими алгоритмами распределения, health checking и автоматическим выводом из ротации упавших серверов.',
      requirements: [
        'Интерфейс LoadBalancer: NextServer() (*Server, error)',
        'Структура Server: URL string, Weight int, Healthy bool, ActiveConns int, TotalRequests int',
        'Алгоритмы: RoundRobin, WeightedRoundRobin, LeastConnections, Random',
        'Health Check: периодический HTTP GET к /health каждому серверу',
        'При ошибке N раз подряд — сервер помечается Healthy=false, исключается из ротации',
        'HTTP reverse proxy: балансировщик проксирует запросы к выбранному серверу',
        'Метрики: запросов на сервер, ошибок, среднее время ответа'
      ],
      expectedOutput: 'RoundRobin: server1, server2, server3, server1, server2...\nWeighted: server1(x3), server2(x2), server3(x1) в пропорции\nLeastConns: выбирает сервер с наименьшим числом активных соединений\nserver2 недоступен -> исключён из ротации\nЗапросы идут только к server1 и server3',
      hint: 'RoundRobin: atomic counter % len(servers). WeightedRoundRobin: список с повторением по весу. LeastConnections: перебирай серверы, выбирай с min ActiveConns. Health check в горутине каждые N сек.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "math/rand"\n    "net/http"\n    "net/http/httputil"\n    "net/url"\n    "sync"\n    "sync/atomic"\n    "time"\n)\n\ntype Server struct {\n    URL           string\n    Weight        int\n    Healthy       bool\n    ActiveConns   int64\n    TotalRequests int64\n    Failures      int\n    proxy         *httputil.ReverseProxy\n    mu            sync.RWMutex\n}\n\nfunc NewServer(rawURL string, weight int) *Server {\n    u, _ := url.Parse(rawURL)\n    return &Server{\n        URL:     rawURL,\n        Weight:  weight,\n        Healthy: true,\n        proxy:   httputil.NewSingleHostReverseProxy(u),\n    }\n}\n\nfunc (s *Server) IsHealthy() bool {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    return s.Healthy\n}\n\ntype LoadBalancer interface {\n    NextServer() (*Server, error)\n    Name() string\n}\n\ntype RoundRobinLB struct {\n    servers []*Server\n    counter uint64\n}\nfunc (lb *RoundRobinLB) Name() string { return "RoundRobin" }\nfunc (lb *RoundRobinLB) NextServer() (*Server, error) {\n    healthy := lb.healthyServers()\n    if len(healthy) == 0 {\n        return nil, fmt.Errorf("нет доступных серверов")\n    }\n    idx := atomic.AddUint64(&lb.counter, 1) % uint64(len(healthy))\n    return healthy[idx], nil\n}\nfunc (lb *RoundRobinLB) healthyServers() []*Server {\n    var result []*Server\n    for _, s := range lb.servers {\n        if s.IsHealthy() {\n            result = append(result, s)\n        }\n    }\n    return result\n}\n\ntype LeastConnectionsLB struct {\n    servers []*Server\n    mu      sync.Mutex\n}\nfunc (lb *LeastConnectionsLB) Name() string { return "LeastConnections" }\nfunc (lb *LeastConnectionsLB) NextServer() (*Server, error) {\n    lb.mu.Lock()\n    defer lb.mu.Unlock()\n    var best *Server\n    for _, s := range lb.servers {\n        if !s.IsHealthy() { continue }\n        if best == nil || atomic.LoadInt64(&s.ActiveConns) < atomic.LoadInt64(&best.ActiveConns) {\n            best = s\n        }\n    }\n    if best == nil {\n        return nil, fmt.Errorf("нет доступных серверов")\n    }\n    return best, nil\n}\n\ntype RandomLB struct{ servers []*Server }\nfunc (lb *RandomLB) Name() string { return "Random" }\nfunc (lb *RandomLB) NextServer() (*Server, error) {\n    var healthy []*Server\n    for _, s := range lb.servers {\n        if s.IsHealthy() { healthy = append(healthy, s) }\n    }\n    if len(healthy) == 0 { return nil, fmt.Errorf("нет доступных серверов") }\n    return healthy[rand.Intn(len(healthy))], nil\n}\n\ntype HealthChecker struct {\n    servers  []*Server\n    interval time.Duration\n    maxFails int\n}\n\nfunc (hc *HealthChecker) Start() {\n    go func() {\n        ticker := time.NewTicker(hc.interval)\n        for range ticker.C {\n            for _, s := range hc.servers {\n                go hc.check(s)\n            }\n        }\n    }()\n}\n\nfunc (hc *HealthChecker) check(s *Server) {\n    client := &http.Client{Timeout: 2 * time.Second}\n    resp, err := client.Get(s.URL + "/health")\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    if err != nil || resp.StatusCode >= 500 {\n        s.Failures++\n        if s.Failures >= hc.maxFails {\n            if s.Healthy {\n                s.Healthy = false\n                fmt.Printf("[HEALTH] %s недоступен -> исключён из ротации\\n", s.URL)\n            }\n        }\n    } else {\n        if !s.Healthy {\n            fmt.Printf("[HEALTH] %s восстановлен -> добавлен в ротацию\\n", s.URL)\n        }\n        s.Healthy = true\n        s.Failures = 0\n        resp.Body.Close()\n    }\n}\n\ntype Proxy struct {\n    lb LoadBalancer\n}\n\nfunc (p *Proxy) ServeHTTP(w http.ResponseWriter, r *http.Request) {\n    server, err := p.lb.NextServer()\n    if err != nil {\n        http.Error(w, err.Error(), http.StatusServiceUnavailable)\n        return\n    }\n    atomic.AddInt64(&server.ActiveConns, 1)\n    atomic.AddInt64(&server.TotalRequests, 1)\n    defer atomic.AddInt64(&server.ActiveConns, -1)\n    server.proxy.ServeHTTP(w, r)\n}\n\nfunc main() {\n    servers := []*Server{\n        NewServer("http://localhost:8081", 3),\n        NewServer("http://localhost:8082", 2),\n        NewServer("http://localhost:8083", 1),\n    }\n    hc := &HealthChecker{servers: servers, interval: 10 * time.Second, maxFails: 3}\n    hc.Start()\n    algorithms := []LoadBalancer{\n        &RoundRobinLB{servers: servers},\n        &LeastConnectionsLB{servers: servers},\n        &RandomLB{servers: servers},\n    }\n    for _, lb := range algorithms {\n        fmt.Printf("\\n=== %s ===" , lb.Name())\n        for i := 0; i < 6; i++ {\n            if s, err := lb.NextServer(); err == nil {\n                fmt.Printf(" -> %s", s.URL)\n            }\n        }\n        fmt.Println()\n    }\n    fmt.Println("\\n=== Симуляция отказа сервера ===")\n    servers[1].mu.Lock()\n    servers[1].Healthy = false\n    servers[1].mu.Unlock()\n    fmt.Printf("server2 отключён\\n")\n    lb := &RoundRobinLB{servers: servers}\n    for i := 0; i < 4; i++ {\n        if s, err := lb.NextServer(); err == nil {\n            fmt.Printf("Запрос %d -> %s\\n", i+1, s.URL)\n        }\n    }\n    proxy := &Proxy{lb: lb}\n    _ = proxy\n    fmt.Println("\\nЗапуск прокси на :8080 (демо)")\n}',
      explanation: 'Балансировщик скрывает детали выбора сервера за интерфейсом LoadBalancer. atomic.AddInt64 для счётчиков без мьютекса — эффективнее для часто обновляемых метрик. LeastConnections выбирает сервер с минимальной нагрузкой — адаптивный подход. Health checker в горутине автоматически исключает упавшие серверы. httputil.ReverseProxy делает фактическое проксирование — не нужно вручную копировать тело запроса/ответа.'
    }
  ]
}
